-- ══════════════════════════════════════════════════════════════════
-- Migration: import v1 data into Hermes v2
-- Strategy: ON CONFLICT — never lose existing data, take the max
-- ══════════════════════════════════════════════════════════════════

BEGIN;

-- ── 1. New tables (user_bump_stats, user_invite_stats) ────────────
CREATE TABLE IF NOT EXISTS user_bump_stats (
    user_id     BIGINT PRIMARY KEY REFERENCES user_voice_data(user_id) ON DELETE CASCADE,
    bump_count  INTEGER DEFAULT 0,
    updated_at  TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_bump_stats_count ON user_bump_stats(bump_count DESC);

CREATE TABLE IF NOT EXISTS user_invite_stats (
    user_id       BIGINT PRIMARY KEY REFERENCES user_voice_data(user_id) ON DELETE CASCADE,
    invite_count  INTEGER DEFAULT 0,
    updated_at    TIMESTAMPTZ DEFAULT NOW()
);
CREATE INDEX IF NOT EXISTS idx_invite_stats_count ON user_invite_stats(invite_count DESC);

-- ── 2. New achievements ───────────────────────────────────────────
ON CONFLICT DO NOTHING;

-- ── 3. Temp tables ────────────────────────────────────────────────
CREATE TEMP TABLE tmp_uvd (
    user_id    BIGINT,
    username   VARCHAR(255),
    total_time INTEGER,
    created_at TIMESTAMPTZ,
    updated_at TIMESTAMPTZ
);

CREATE TEMP TABLE tmp_ums (
    user_id       BIGINT,
    channel_id    BIGINT,
    message_count INTEGER,
    created_at    TIMESTAMPTZ,
    updated_at    TIMESTAMPTZ
);

CREATE TEMP TABLE tmp_ubs (
    user_id        BIGINT,
    bump_count     INTEGER,
    last_bump_time TIMESTAMPTZ,
    created_at     TIMESTAMPTZ,
    updated_at     TIMESTAMPTZ
);

CREATE TEMP TABLE tmp_warn (
    id           INTEGER,
    user_id      BIGINT,
    reason       TEXT,
    create_time  BIGINT,
    moderator_id BIGINT
);

-- ── 4. COPY data into temp tables ──────────────────────────────




-- ── 5. Merge user_voice_data ──────────────────────────────────────
-- Insert new users; for existing ones, update voice time (take max)
SELECT user_id, username, total_time, updated_at, created_at, updated_at
FROM tmp_uvd
ON CONFLICT (user_id) DO UPDATE
  SET username   = EXCLUDED.username,
      total_time = GREATEST(user_voice_data.total_time, EXCLUDED.total_time),
      last_seen  = GREATEST(user_voice_data.last_seen, EXCLUDED.last_seen),
      updated_at = NOW();

-- ── 6. Merge user_message_stats ───────────────────────────────────
-- Only for users that exist (FK safety); take the max message_count
SELECT t.user_id, t.channel_id, t.message_count, t.created_at, t.updated_at
FROM tmp_ums t
WHERE EXISTS (SELECT 1 FROM user_voice_data v WHERE v.user_id = t.user_id)
ON CONFLICT (user_id, channel_id) DO UPDATE
  SET message_count = GREATEST(user_message_stats.message_count, EXCLUDED.message_count),
      updated_at    = NOW();

-- ── 7. Merge user_bump_stats ──────────────────────────────────────
SELECT t.user_id, t.bump_count, t.last_bump_time
FROM tmp_ubs t
WHERE EXISTS (SELECT 1 FROM user_voice_data v WHERE v.user_id = t.user_id)
ON CONFLICT (user_id) DO UPDATE
  SET bump_count = GREATEST(user_bump_stats.bump_count, EXCLUDED.bump_count),
      updated_at = GREATEST(user_bump_stats.updated_at, EXCLUDED.updated_at);

-- ── 8. Merge warn ─────────────────────────────────────────────────
-- Skip rows with conflicting IDs (already present)
SELECT t.id, t.user_id, t.reason, t.create_time, t.moderator_id
FROM tmp_warn t
WHERE EXISTS (SELECT 1 FROM user_voice_data v WHERE v.user_id = t.user_id)
ON CONFLICT DO NOTHING;

-- Fix warn sequence to avoid future ID collisions
SELECT setval('warn_id_seq', COALESCE((SELECT MAX(id) FROM warn), 0) + 1, false);

-- ── 9. Summary ────────────────────────────────────────────────────
SELECT 'user_voice_data'  AS tbl, COUNT(*) FROM user_voice_data UNION ALL
SELECT 'user_message_stats',      COUNT(*) FROM user_message_stats UNION ALL
SELECT 'user_bump_stats',         COUNT(*) FROM user_bump_stats UNION ALL
SELECT 'warn',                    COUNT(*) FROM warn UNION ALL
SELECT 'achievements',            COUNT(*) FROM achievements;

COMMIT;
